Sec={addListeners:function(type,elements,listener){for(let index=0;index<elements.length;index++){const el=elements[index];el.addEventListener(type,listener)}},initLanguage:function(){const logoImg=document.getElementById("logo");const collageImg=document.getElementById("collage");const collageMobileImg=document.getElementById("collageMobile");const url=window.location.pathname;let lang=null;if(url.includes("/en/")){lang="en"}else if(url.includes("/fr/")){lang="fr"}if(lang&&logoImg){logoImg.parentElement.href=`/${lang}/`;logoImg.src=logoImg.getAttribute(lang)}if(lang&&collageImg){collageImg.src=collageImg.getAttribute(lang)}if(lang&&collageMobileImg){collageMobileImg.src=collageMobileImg.getAttribute(lang)}},initCarousel:function(){Sec.carousel=document.querySelector(".carousel");Sec.slides=document.querySelectorAll(".carousel-slide");Sec.prevButton=document.querySelector(".prev-btn");Sec.nextButton=document.querySelector(".next-btn");Sec.pagination=document.querySelector(".carousel-pagination");if(!Sec.carousel||!Sec.slides.length||!Sec.pagination){return}let currentIndex=0;
// Vytvoření pagination teček
Sec.slides.forEach((slide,index)=>{const dot=document.createElement("span");dot.addEventListener("click",()=>goToSlide(index));Sec.pagination.appendChild(dot)});updatePagination();function goToSlide(index){if(index<0)index=Sec.slides.length-1;if(index>=Sec.slides.length)index=0;currentIndex=index;updateCarousel();updatePagination()}function updateCarousel(){const offset=-currentIndex*100;Sec.carousel.style.transform=`translateX(${offset}%)`}function updatePagination(){const dots=Sec.pagination.querySelectorAll("span");dots.forEach((dot,index)=>{dot.classList.toggle("active",index===currentIndex)})}
// Ovládací prvky
if(Sec.prevButton){Sec.prevButton.addEventListener("click",()=>goToSlide(currentIndex-1))}if(Sec.nextButton){Sec.nextButton.addEventListener("click",()=>goToSlide(currentIndex+1))}
// Auto-slide
setInterval(()=>goToSlide(currentIndex+1),12e3)},openPreview:function(){const img=document.getElementById("modalImage");img.src=this.src;img.alt=this.alt;document.getElementById("caption").innerHTML=this.alt;document.body.classList.add("modalIsOpen")},closePreview:function(){document.body.classList.remove("modalIsOpen")},openMenu:function(){document.body.classList.add("menuIsOpen")},closeMenu:function(){document.body.classList.remove("menuIsOpen")}};document.addEventListener("DOMContentLoaded",function(){Sec.modal=document.getElementById("modal");Sec.menuOpeners=document.querySelectorAll(".menuOpener");Sec.menuClosers=document.querySelectorAll(".menuCloser");Sec.galleryImgs=document.querySelectorAll(".gallery img");Sec.addListeners("click",Sec.galleryImgs,Sec.openPreview);Sec.addListeners("click",Sec.menuOpeners,Sec.openMenu);Sec.addListeners("click",Sec.menuClosers,Sec.closeMenu);if(Sec.modal){Sec.modal.addEventListener("click",Sec.closePreview)}Sec.initCarousel();Sec.initLanguage()});